// Generar semanas (lunes a domingo) desde 2025-01-01 hasta hoy
var now = new Date();
var end = new Date(now.getFullYear(), now.getMonth(), now.getDate());
var cur = new Date(2025, 0, 1);  // 2025-01-01
// Ajustar al lunes de esa semana
var dow = cur.getDay();  // 0=Dom, 1=Lun...
var adj = dow === 0 ? -6 : 1 - dow;
cur.setDate(cur.getDate() + adj);

var weeks = [];
while (cur <= end) {
  var ws = new Date(cur);
  var we = new Date(cur);
  we.setDate(we.getDate() + 6);
  if (we > end) we = new Date(end);
  var sd = ws.getFullYear() + String(ws.getMonth()+1).padStart(2,'0') + String(ws.getDate()).padStart(2,'0');
  var ed = we.getFullYear() + String(we.getMonth()+1).padStart(2,'0') + String(we.getDate()).padStart(2,'0');
  weeks.push({ sd: sd, ed: ed, label: sd + '-' + ed });
  cur.setDate(cur.getDate() + 7);
}

msg._weeks = weeks;
msg._idx = 0;
msg._accum = [];
msg._sync_uuid = (Date.now().toString(36).toUpperCase().slice(-4) + Math.random().toString(36).substring(2,6).toUpperCase() + Math.random().toString(36).substring(2,6).toUpperCase());
msg._startDate = weeks.length > 0 ? weeks[0].sd : '';
msg._endDate = weeks.length > 0 ? weeks[weeks.length-1].ed : '';
node.warn('[Sync-ss] Iniciando ' + weeks.length + ' semanas (SumasSaldos)');
return msg;

var rows = msg.payload || [];
if (rows.length > 0) {
  for (var i = 0; i < rows.length; i++) msg._accum.push(rows[i]);
}
msg._idx++;
if (msg._idx < msg._weeks.length) return [msg, null];
node.warn('[Sync-SS] Loop completado. ' + msg._accum.length + ' filas totales. Mergeando por CODIGO...');
// Acumular por CODIGO + UNIDAD_NEGOCIO
var map = {};
for (var i = 0; i < msg._accum.length; i++) {
  var r = msg._accum[i];
  var key = (r.CODIGO || '') + '|' + (r.UNIDAD_NEGOCIO || '');
  if (!map[key]) map[key] = { CODIGO: r.CODIGO, CUENTA: r.CUENTA, CRubro: r.CRubro, NRubro: r.NRubro, UNIDAD_NEGOCIO: r.UNIDAD_NEGOCIO || '', DEBE: 0, HABER: 0 };
  map[key].DEBE += parseFloat(r.DEBE) || 0;
  map[key].HABER += parseFloat(r.HABER) || 0;
}
msg._merged = [];
var keys = Object.keys(map).sort();
for (var k = 0; k < keys.length; k++) msg._merged.push(map[keys[k]]);
node.warn('[Sync-SS] ' + msg._merged.length + ' cuentas unicas (mergeado)');
return [null, msg];

var merged = msg._merged || [];
var timestamp = new Date().toISOString();
var periodo = msg._startDate + '-' + msg._endDate;
msg._syncInfo = { sync_uuid: msg._sync_uuid, periodo: periodo, timestamp: timestamp };
if (merged.length === 0) { msg._syncInfo.empty = true; msg.payload = null; return msg; }
var data = [];
for (var i = 0; i < merged.length; i++) {
  var r = merged[i], debe = r.DEBE || 0, haber = r.HABER || 0;
  data.push([r.CODIGO||'', r.CUENTA||'', r.NRubro||'', debe, haber, debe-haber, periodo, timestamp, msg._sync_uuid, r.UNIDAD_NEGOCIO||'']);
}
msg._sheetData = data; msg.payload = data;
msg._syncInfo.rowCount = data.length;
node.warn('[Sync-SS] ' + data.length + ' filas finales (10 cols A-J)');
return msg;

var info = msg._syncInfo || {};
if (info.empty) { node.warn('[Sync-ss] ⚠ Sin datos'); }
if (msg.error) { node.error('[Sync-ss] ERROR: ' + msg.error); }
else { node.warn('[Sync-ss] ✅ ' + (info.rowCount || 0) + ' filas → SumasSaldos'); }
return msg;

