//   NOMBREOPERADORCOMERCIAL, ORIGEN, NETO, VALORTOTAL, NOMCLASIFICADOR
var q = ""
+ "SELECT TOP 1000\n"
+ "    SUBSTRING(FECHAEMISION, 1, 8) AS FECHA,\n"
+ "    DESCRIPCION,\n"
+ "    COMPROBANTE,\n"
+ "    NOMBREOPERADORCOMERCIAL AS ENTE,\n"
+ "    ORIGEN,\n"
+ "    ROUND(NETO, 2) AS NETO,\n"
+ "    ROUND(VALORTOTAL - NETO, 2) AS IVA,\n"
+ "    ROUND(VALORTOTAL, 2) AS TOTAL,\n"
+ "    NOMCLASIFICADOR AS CLASIFICADOR\n"
+ "FROM V_EZI_IMPUTACIONES_C\n"
+ "WHERE SUBSTRING(FECHAEMISION, 1, 8) >= '" + startDate + "'\n"
+ "  AND SUBSTRING(FECHAEMISION, 1, 8) <= '" + endDate + "'\n"
+ "  AND NETO IS NOT NULL\n"
+ "ORDER BY FECHAEMISION DESC;\n";

msg.payload = q;
node.warn('[Sync-IMP] Preparando sync ' + sync_uuid);
return msg;

