  var r = rows[i]; if (!r) continue;

  // Derivar tipo desde DESCRIPCION
  var desc = (r.DESCRIPCION || '').toString();
  var tipo = 'OTRO';
  if (desc.indexOf('Fact.Cpra.') > -1 || desc.indexOf('Fact.B') > -1) tipo = 'COMPRA';
  else if (desc.indexOf('Fact.Vta.') > -1 || desc.indexOf('Fact.A') > -1) tipo = 'VENTA';
  else if (desc.indexOf('NC.') > -1 || desc.indexOf('ND.') > -1) tipo = 'AJUSTE';
  else if (desc.indexOf('Rec.') > -1) tipo = 'GASTO';
  else if (desc.indexOf('Pago') > -1) tipo = 'PAGO';

  var comp = (r.COMPROBANTE || '').toString().trim();
  var ente = (r.ENTE || '').toString().trim();
  var cc = (r.CLASIFICADOR || '').toString().trim();
  var neto = parseFloat(r.NETO) || 0;
  var iva = parseFloat(r.IVA) || 0;
  var total = parseFloat(r.TOTAL) || 0;

  data.push([
    (r.FECHA || '').toString().trim(),
    tipo,
    comp,
    ente,
    cc,
    neto,
    iva,
    total,
    cc,  // UNIDAD_NEGOCIO = CLASIFICADOR (BLC, SAS, etc.)
    sync_uuid
  ]);
}
