return msg;

var now = new Date();
var y = now.getFullYear(); var m = String(now.getMonth() + 1).padStart(2, '0');
var lastDay = new Date(y, now.getMonth() + 1, 0).getDate();
var startDate = '20250101'; var endDate = y + m + String(lastDay).padStart(2, '0');
var sync_uuid = (Date.now().toString(36).toUpperCase().slice(-4) + Math.random().toString(36).substring(2,6).toUpperCase() + Math.random().toString(36).substring(2,6).toUpperCase());
msg.startDate = startDate; msg.endDate = endDate; msg.sync_uuid = sync_uuid;

// V_TRANSACCION: movimientos entre Bioenergia La Corona ↔ Sucroalcoholera del Sur
var q = ""
+ "SELECT TOP 500\n"
+ "    SUBSTRING(FECHAACTUAL, 1, 8) AS FECHA,\n"
+ "    NOMBREORIGINANTE AS DESDE,\n"
+ "    NOMBREDESTINATARIO AS HACIA,\n"
+ "    COALESCE(NULLIF(DETALLE,''), NUMERODOCUMENTO) AS CONCEPTO,\n"
+ "    NUMERODOCUMENTO AS COMPROBANTE,\n"
+ "    ROUND(VALORTOTAL, 2) AS IMPORTE,\n"
+ "    NOMBREMONEDA AS MONEDA\n"
+ "FROM V_TRANSACCION\n"
+ "WHERE SUBSTRING(FECHAACTUAL, 1, 8) >= '" + startDate + "'\n"
+ "  AND SUBSTRING(FECHAACTUAL, 1, 8) <= '" + endDate + "'\n"
+ "  AND (\n"
+ "    (NOMBREORIGINANTE LIKE '%BIOENERGIA%CORONA%' AND NOMBREDESTINATARIO LIKE '%SUCROALCOHOLERA%SUR%')\n"
+ "    OR (NOMBREORIGINANTE LIKE '%SUCROALCOHOLERA%SUR%' AND NOMBREDESTINATARIO LIKE '%BIOENERGIA%CORONA%')\n"
+ "  )\n"
+ "ORDER BY FECHAACTUAL DESC;\n";

msg.payload = q;
node.warn('[Sync-INTER] Preparando sync ' + sync_uuid);
return msg;

var rows = msg.payload;
var sync_uuid = msg.sync_uuid || 'N/A';
var timestamp = new Date().toISOString();
msg._syncInfo = { sync_uuid: sync_uuid, periodo: (msg.startDate||'')+'-'+(msg.endDate||''), timestamp: timestamp };
if (!rows || !Array.isArray(rows) || rows.length === 0) {
  node.warn('[Sync-INTER] Sin datos.'); msg._syncInfo.empty = true; msg.payload = null; return msg;
}
// Columnas A-J: FECHA|DESDE|HACIA|CONCEPTO|COMPROBANTE|IMPORTE|TIPO|MONEDA|UNIDAD_NEGOCIO|SYNC_UUID
var data = [];
for (var i = 0; i < rows.length; i++) {
  var r = rows[i]; if (!r) continue;

  var desde = (r.DESDE || '').toString().trim();
  var hacia = (r.HACIA || '').toString().trim();
  var importe = parseFloat(r.IMPORTE) || 0;
  if (importe === 0) continue;  // Saltar movimientos sin importe

  // Determinar tipo desde la perspectiva de Bioenergia La Corona
  var tipo = 'salida';
  if (desde.indexOf('SUCROALCOHOLERA') > -1 && hacia.indexOf('BIOENERGIA') > -1) {
    tipo = 'entrada';
  }

  // Simplificar nombres para el frontend
  desde = desde.replace('2-BIOENERGIA LA CORONA S.A.', 'Ingenio La Corona')
               .replace('5-SUCROALCOHOLERA DEL SUR S.A.', 'Destilería Corona S.A.');
  hacia = hacia.replace('2-BIOENERGIA LA CORONA S.A.', 'Ingenio La Corona')
               .replace('5-SUCROALCOHOLERA DEL SUR S.A.', 'Destilería Corona S.A.');

  data.push([
    (r.FECHA || '').toString().trim(),
    desde,
    hacia,
    (r.CONCEPTO || '').toString().trim(),
    (r.COMPROBANTE || '').toString().trim(),
    importe,
    tipo,
    (r.MONEDA || '').toString().trim(),
    '',  // UNIDAD_NEGOCIO (vacío para interempresas — aplica a todo el grupo)
    sync_uuid
  ]);
}
msg._sheetData = data; msg.payload = data;
msg._syncInfo.rowCount = data.length;
node.warn('[Sync-INTER] ' + data.length + ' movimientos interempresas. UUID=' + sync_uuid);
return msg;

// El GSheet Clear sobreescribe msg.payload con la respuesta de la API
// Restaurar el array 2D desde _sheetData para que el Append funcione
if (msg._sheetData) {
  msg.payload = msg._sheetData;
}
return msg;

var info = msg._syncInfo || {};
if (info.empty) {
  node.warn('[Sync-INTER] Sync omitido: sin datos');
  return msg;
}
if (msg.error) {
  node.error('[Sync-INTER] ERROR: ' + msg.error);
  return msg;
}
var updatedRange = '';
if (msg.payload && msg.payload.updates) updatedRange = msg.payload.updates.updatedRange || '';
node.warn('[Sync-SYS] 🎉 Sync completo del tablero. 9 pestañas actualizadas.');
node.warn('[Sync-INTER] ✅ Sync exitoso — ' + (info.rowCount || 0) + ' filas → Interempresas');
node.warn('[Sync-INTER]    UUID: ' + (info.sync_uuid || '?') + ' | Rango: ' + updatedRange);
return msg;
